function validateEmail(email) {
    const atCount = (email.match(/@/g) || []).length;
    if (atCount !== 1) {
        return false;
    }
    const atIndex = email.indexOf('@');
    const afterAt = email.substring(atIndex + 1);
    if (!afterAt.includes('.')) {
        return false;
    }
    return true;
}
