import pytest


def is_even(n):
    """Returns True if n is even, False otherwise."""
    return n % 2 == 0


class TestIsEven:
    def test_positive_even(self):
        assert is_even(4) is True

    def test_positive_odd(self):
        assert is_even(3) is False

    def test_zero(self):
        assert is_even(0) is True
